class FenwickTree:
    def __init__(self, size):
        self.n = size
        self.tree = [0] * (self.n + 1)

    def update(self, idx, delta):
        while idx <= self.n:
            self.tree[idx] += delta
            idx += idx & -idx

    def query(self, idx):
        res = 0
        while idx > 0:
            res += self.tree[idx]
            idx -= idx & -idx
        return res

    def range_query(self, l, r):
        return self.query(r) - self.query(l - 1)

def get_depth(x):
    depth = 0
    while x != 1:
        x = bin(x).count('1')
        depth += 1
    return depth

def solve(nums: list[int], queries: list[list[int]]) -> list[int]:
    n = len(nums)
    ft = [FenwickTree(n) for _ in range(6)]
    depths = [0] * n
    for i in range(n):
        x = nums[i]
        d = get_depth(x)
        depths[i] = d
        if d <= 5:
            ft[d].update(i + 1, 1)
    answer = []
    for q in queries:
        if q[0] == 1:
            l = q[1]
            r = q[2]
            k = q[3]
            if k < 0 or k > 5:
                answer.append(0)
                continue
            res = ft[k].range_query(l + 1, r + 1)
            answer.append(res)
        else:
            idx = q[1]
            val = q[2]
            old_d = depths[idx]
            if old_d <= 5:
                ft[old_d].update(idx + 1, -1)
            nums[idx] = val
            new_d = get_depth(val)
            depths[idx] = new_d
            if new_d <= 5:
                ft[new_d].update(idx + 1, 1)
    return answer
